import { Info } from "lucide-react";
import { useState, useEffect } from "react";

const MONTH_LABELS = [
  "Jan", "Feb", "Mar", "Apr", "May", "Jun", 
  "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"
];

const LEVEL_COLORS = [
  "bg-muted/30 dark:bg-[#1f2328]",
  "bg-emerald-100 dark:bg-emerald-900/30",
  "bg-emerald-300 dark:bg-emerald-700/50",
  "bg-emerald-500 dark:bg-emerald-500/70",
  "bg-emerald-700 dark:bg-emerald-400"
];

export function ContributionGraph({ stats: externalStats }: { stats?: any }) {
  const stats = externalStats || { totalSubmissions: 0, activeDays: 0 };

  const getDayColor = (level: number) => {
    return LEVEL_COLORS[level] || LEVEL_COLORS[0];
  };

  return (
    <div className="rounded-[2.5rem] border border-foreground/10 bg-card/40 p-8 pt-7 backdrop-blur-3xl shadow-2xl transition-all duration-500 premium-border relative overflow-hidden group/contributions mt-6 hover:-translate-y-1 hover:shadow-primary/5 hover:border-primary/20 cursor-default">
      {/* Glossy Overlay */}
      <div className="absolute inset-0 bg-gradient-to-br from-foreground/[0.03] to-transparent pointer-events-none" />

      {/* Top Header */}
      <div className="relative z-10 flex items-center justify-between mb-8 px-2">
        <div className="flex flex-col gap-1.5">
          <div className="flex items-center gap-2">
            <div className="h-2 w-2 rounded-full bg-primary shadow-[0_0_8px_hsla(var(--primary),0.5)] animate-pulse" />
            <h4 className="text-[10px] font-black text-muted-foreground uppercase tracking-[0.3em] font-mono leading-none">
              Activity Matrix
            </h4>
          </div>
          <div className="flex items-center gap-2">
            <h3 className="text-2xl font-black tracking-tight text-foreground">
              {stats?.totalSubmissions !== undefined ? stats.totalSubmissions.toLocaleString() : "0"} Submissions
            </h3>
            <span className="text-xs text-muted-foreground font-mono opacity-40">in the past year</span>
          </div>
        </div>

        <div className="flex flex-col items-end">
          <span className="text-[10px] text-muted-foreground/40 font-mono uppercase tracking-widest font-black">Total Active</span>
          <span className="text-sm font-black text-primary tabular-nums tracking-tight italic">
            {stats?.activeDays || 0} Days streak
          </span>
        </div>
      </div>

      {/* Grid Canvas - 12 Monthly Boxes with centered labels */}
      <div className="relative z-10 overflow-x-auto pb-4 custom-scrollbar">
        <div className="min-w-fit px-2">
          <div
            style={{
              display: "flex",
              gap: "28px", // Slightly more spacing for that premium look
            }}
          >
            {MONTH_LABELS.map((month) => (
              <div key={month} className="flex flex-col gap-3">
                {/* Centered Month Label */}
                <span className="text-[10px] text-muted-foreground/50 font-black font-mono uppercase tracking-[0.2em] text-center w-full">
                  {month}
                </span>

                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(4, 15px)", 
                    gridTemplateRows: "repeat(7, 15px)",
                    gap: "5px"
                  }}
                  className="rounded-xl"
                >
                  {Array.from({ length: 4 * 7 }).map((_, i) => {
                    // Generate dummy level weighted towards 0 and 1, with occasional higher levels
                    const rand = Math.random();
                    let level = 0;
                    if (rand > 0.6) level = 1;
                    if (rand > 0.8) level = 2;
                    if (rand > 0.9) level = 3;
                    if (rand > 0.95) level = 4;

                    return (
                      <div
                        key={i}
                        className={`${getDayColor(level)} w-[15px] h-[15px] rounded-[4px] border border-foreground/5 transition-all duration-300 cursor-pointer hover:border-primary/50 hover:shadow-[0_0_10px_hsla(var(--primary),0.2)] hover:scale-110 active:scale-95`}
                        title={level > 0 ? `${Math.floor(Math.random() * 8) + 1} submissions on this day` : "No activity recorded"}
                      />
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Legend & Info */}
      <div className="relative z-10 flex items-center justify-between mt-6 px-2">
        <div className="flex items-center gap-2 group/info cursor-help">
          <Info className="h-3.5 w-3.5 text-muted-foreground/30 transition-colors group-hover/info:text-primary" />
          <span className="text-[9px] font-black text-muted-foreground/40 uppercase tracking-widest font-mono">Real-time sync</span>
        </div>

        <div className="flex items-center gap-3 bg-muted/10 px-4 py-2 rounded-full border border-white/5 transition-colors hover:border-white/10 shadow-inner">
          <span className="text-[9px] text-muted-foreground font-black font-mono uppercase tracking-widest">Less</span>
          <div className="flex gap-[4px]">
            {LEVEL_COLORS.map((colorClass, index) => (
              <div 
                key={index} 
                className={`w-[11px] h-[11px] rounded-[3px] ${colorClass} border border-foreground/5 transition-transform hover:scale-110`} 
              />
            ))}
          </div>
          <span className="text-[9px] text-muted-foreground font-black font-mono uppercase tracking-widest">More</span>
        </div>
      </div>

      {/* Background Decorative Element */}
      <div className="absolute -bottom-10 -right-10 w-48 h-48 bg-primary/5 blur-[80px] rounded-full pointer-events-none transition-opacity duration-1000 group-hover/contributions:opacity-100 opacity-50" />
    </div>
  );
}

import { motion } from "framer-motion";
import { useDashboard } from "@/hooks/useDashboard";
import { Star, TrendingUp, Award, Hash } from "lucide-react";

function StatBox({ label, value, color }: { label: string; value: string | number; color: string }) {
  return (
    <div className="flex flex-col items-center justify-center p-3 rounded-xl bg-background/40 border border-border/40 backdrop-blur-sm shadow-inner">
      <span className={`text-2xl font-black font-heading ${color}`}>{value}</span>
      <span className="text-[10px] text-muted-foreground uppercase tracking-widest font-mono font-bold mt-1">{label}</span>
    </div>
  );
}

function PlatformCard({ 
  name, 
  icon: Icon, 
  colorClass, 
  borderColor, 
  gradientColor, 
  stats, 
  delay 
}: { 
  name: string; 
  icon: any; 
  colorClass: string; 
  borderColor: string; 
  gradientColor: string; 
  stats: { solved: number; rating: number; contests: number };
  delay: number;
}) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 24 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay, duration: 0.5 }}
      whileHover={{ y: -4 }}
      className={`group relative rounded-3xl border ${borderColor} bg-gradient-to-br ${gradientColor} p-6 backdrop-blur-md overflow-hidden card-hover`}
    >
      <div className="absolute inset-0 bg-gradient-to-br from-foreground/[0.03] to-transparent pointer-events-none" />

      <div className="relative">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-3">
            <div className={`h-10 w-10 rounded-xl bg-background/50 border ${borderColor} flex items-center justify-center shadow-inner`}>
              <Icon className={`h-5 w-5 ${colorClass}`} />
            </div>
            <h3 className="text-base font-heading font-bold text-foreground">{name}</h3>
          </div>
          <div className={`px-2 py-1 rounded-full bg-background/30 border ${borderColor} text-[10px] font-mono ${colorClass} font-bold`}>
            ACTIVE
          </div>
        </div>

        <div className="mb-8 text-center">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em] font-mono font-black mb-1">Total Problems Solved</p>
          <p className={`text-6xl font-black font-heading ${colorClass} tracking-tighter`}>
            {stats.solved}
          </p>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <StatBox label="Contest Rating" value={stats.rating} color={colorClass} />
          <StatBox label="Total Contests" value={stats.contests} color={colorClass} />
        </div>
      </div>
    </motion.div>
  );
}

export function PlatformCards({ stats }: { stats?: any }) {
  const platforms = [
    {
      name: "LeetCode",
      icon: Hash,
      colorClass: "text-leetcode",
      borderColor: "border-leetcode/20",
      gradientColor: "from-leetcode/10 to-leetcode/5",
      stats: {
        solved: stats?.leetcode || 250,
        rating: stats?.leetcodeRating || 1982,
        contests: stats?.leetcodeContests || 45
      },
      delay: 0.4
    },
    {
      name: "Codeforces",
      icon: TrendingUp,
      colorClass: "text-codeforces",
      borderColor: "border-codeforces/20",
      gradientColor: "from-codeforces/10 to-codeforces/5",
      stats: {
        solved: stats?.codeforces || 120,
        rating: stats?.codeforcesRating || 1650,
        contests: stats?.codeforcesContests || 28
      },
      delay: 0.5
    },
    {
      name: "CodeChef",
      icon: Award,
      colorClass: "text-codechef",
      borderColor: "border-codechef/20",
      gradientColor: "from-codechef/10 to-codechef/5",
      stats: {
        solved: stats?.codechef || 112,
        rating: stats?.codechefRating || 1820,
        contests: stats?.codechefContests || 38
      },
      delay: 0.6
    }
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
      {platforms.map((p) => (
        <PlatformCard key={p.name} {...p} />
      ))}
    </div>
  );
}

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, Area, AreaChart } from "recharts";
import { useDashboard } from "@/hooks/useDashboard";
import { TrendingUp } from "lucide-react";

type Platform = "codeforces" | "leetcode";

const platformConfig: Record<Platform, { label: string; color: string; cssColor: string; gradient: string }> = {
  codeforces: { label: "Codeforces", color: "hsl(215, 80%, 55%)", cssColor: "text-codeforces", gradient: "from-codeforces/20" },
  leetcode: { label: "LeetCode", color: "hsl(36, 100%, 50%)", cssColor: "text-leetcode", gradient: "from-leetcode/20" },
};

export function RatingGraph({ userId }: { userId?: string }) {
  const [platform, setPlatform] = useState<Platform>("codeforces");
  const { data: dash } = useDashboard(userId);
  const ratingHistory = dash?.ratingHistory;
  const data = (ratingHistory?.[platform] || []) as any[];
  const config = platformConfig[platform];
  const latest = data[data.length - 1] || { rating: 0 };
  const prev = data[data.length - 2] || latest;
  const delta = (latest?.rating || 0) - (prev?.rating || 0);

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.65 }}
      className="rounded-2xl border border-border/60 bg-card/60 backdrop-blur-xl p-5 h-full"
    >
      <div className="flex items-center justify-between mb-5">
        <div className="flex items-center gap-2.5">
          <div className="p-1.5 rounded-lg bg-secondary">
            <TrendingUp className="h-4 w-4 text-foreground" />
          </div>
          <div>
            <h3 className="text-sm font-heading font-semibold text-foreground">Rating History</h3>
            <div className="flex items-center gap-2 mt-0.5">
              <span className={`text-xs font-mono font-bold ${config.cssColor}`}>{latest.rating}</span>
              <span className={`text-[10px] font-mono ${delta >= 0 ? "text-primary" : "text-destructive"}`}>
                {delta >= 0 ? "+" : ""}{delta}
              </span>
            </div>
          </div>
        </div>
        <div className="flex gap-1 rounded-xl bg-muted/80 p-1 border border-border/50">
          {(Object.keys(platformConfig) as Platform[]).map((p) => (
            <button
              key={p}
              onClick={() => setPlatform(p)}
              className={`relative px-3.5 py-1.5 rounded-lg text-xs font-mono transition-all duration-200 ${
                platform === p
                  ? `bg-card shadow-sm ${platformConfig[p].cssColor} font-semibold`
                  : "text-muted-foreground hover:text-foreground"
              }`}
            >
              {platformConfig[p].label}
            </button>
          ))}
        </div>
      </div>
      <div className="h-[220px]">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={data}>
            <defs>
              <linearGradient id={`gradient-${platform}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={config.color} stopOpacity={0.2} />
                <stop offset="100%" stopColor={config.color} stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="hsl(228, 12%, 14%)" />
            <XAxis
              dataKey="contest"
              tick={{ fontSize: 10, fill: "hsl(215, 12%, 40%)" }}
              axisLine={{ stroke: "hsl(228, 12%, 14%)" }}
              tickLine={false}
            />
            <YAxis
              tick={{ fontSize: 10, fill: "hsl(215, 12%, 40%)" }}
              axisLine={false}
              tickLine={false}
              domain={["dataMin - 50", "dataMax + 50"]}
            />
            <Tooltip
              contentStyle={{
                backgroundColor: "hsl(228, 14%, 10%)",
                border: "1px solid hsl(228, 12%, 18%)",
                borderRadius: "12px",
                fontSize: "12px",
                fontFamily: "JetBrains Mono",
                boxShadow: "0 8px 32px rgba(0,0,0,0.4)",
              }}
              labelStyle={{ color: "hsl(210, 20%, 92%)" }}
            />
            <Area
              type="monotone"
              dataKey="rating"
              stroke={config.color}
              strokeWidth={2.5}
              fill={`url(#gradient-${platform})`}
              dot={{ fill: config.color, r: 4, strokeWidth: 2, stroke: "hsl(228, 14%, 10%)" }}
              activeDot={{ r: 6, strokeWidth: 3, stroke: "hsl(228, 14%, 10%)" }}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </motion.div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Play, RotateCcw, Eye } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

type Activity = "deep" | "box" | "eyes";

/* ─── Deep Breathing ─── */
function DeepBreathing() {
  const [phase, setPhase] = useState<"inhale" | "hold" | "exhale">("inhale");
  const [active, setActive] = useState(false);
  const [count, setCount] = useState(4);

  const PHASES: { name: "inhale" | "hold" | "exhale"; label: string; duration: number; color: string }[] = [
    { name: "inhale", label: "Inhale", duration: 4, color: "from-sky-400/30 to-primary/20" },
    { name: "hold", label: "Hold", duration: 2, color: "from-violet-400/30 to-primary/20" },
    { name: "exhale", label: "Exhale", duration: 6, color: "from-emerald-400/30 to-primary/10" },
  ];

  const currentPhase = PHASES.find((p) => p.name === phase)!;

  useEffect(() => {
    if (!active) return;
    const id = setInterval(() => {
      setCount((c) => {
        if (c <= 1) {
          setPhase((prev) => {
            const idx = PHASES.findIndex((p) => p.name === prev);
            const next = PHASES[(idx + 1) % PHASES.length];
            return next.name;
          });
          return currentPhase.duration;
        }
        return c - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [active, phase]);

  const reset = () => { setActive(false); setPhase("inhale"); setCount(4); };

  return (
    <div className="flex flex-col items-center gap-8">
      <p className="font-mono text-sm text-muted-foreground text-center max-w-xs">
        4-2-6 breathing: inhale for 4s, hold for 2s, exhale for 6s. Activates your parasympathetic nervous system.
      </p>
      <div className="relative flex items-center justify-center h-48 w-48">
        {/* Outer pulse rings */}
        {active && (
          <>
            <motion.div
              className={cn("absolute rounded-full bg-gradient-to-br opacity-20", currentPhase.color)}
              animate={phase === "inhale" ? { scale: [1, 1.8], opacity: [0.3, 0] } : phase === "exhale" ? { scale: [1.8, 1], opacity: [0, 0.3] } : { scale: 1.8 }}
              transition={{ duration: currentPhase.duration, ease: "easeInOut" }}
              style={{ width: "100%", height: "100%" }}
            />
          </>
        )}
        {/* Main circle */}
        <motion.div
          className={cn("flex flex-col items-center justify-center rounded-full border-2 border-primary/30 bg-gradient-to-br", currentPhase.color)}
          animate={active
            ? phase === "inhale" ? { scale: 1.4 } : phase === "exhale" ? { scale: 0.8 } : { scale: 1.2 }
            : { scale: 1 }
          }
          transition={{ duration: currentPhase.duration, ease: "easeInOut" }}
          style={{ width: "140px", height: "140px" }}
        >
          <span className="font-heading text-3xl font-bold text-foreground">{active ? count : "·"}</span>
          <span className="font-mono text-xs text-muted-foreground capitalize">{active ? currentPhase.label : "Ready"}</span>
        </motion.div>
      </div>

      <div className="flex gap-3">
        <Button variant="outline" size="sm" onClick={reset} className="rounded-xl gap-2 font-mono text-xs">
          <RotateCcw className="h-3.5 w-3.5" /> Reset
        </Button>
        <Button size="sm" onClick={() => setActive((a) => !a)} className="rounded-xl gap-2 font-mono text-xs">
          <Play className="h-3.5 w-3.5" /> {active ? "Pause" : "Start"}
        </Button>
      </div>
    </div>
  );
}

/* ─── Box Breathing ─── */
function BoxBreathing() {
  const SIDES = ["Inhale", "Hold", "Exhale", "Hold"] as const;
  const [step, setStep] = useState(0);
  const [count, setCount] = useState(4);
  const [active, setActive] = useState(false);

  useEffect(() => {
    if (!active) return;
    const id = setInterval(() => {
      setCount((c) => {
        if (c <= 1) {
          setStep((s) => (s + 1) % 4);
          return 4;
        }
        return c - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [active]);

  const reset = () => { setActive(false); setStep(0); setCount(4); };

  const boxColors = [
    "border-sky-400/60 bg-sky-400/10",
    "border-violet-400/60 bg-violet-400/10",
    "border-emerald-400/60 bg-emerald-400/10",
    "border-amber-400/60 bg-amber-400/10",
  ];

  return (
    <div className="flex flex-col items-center gap-8">
      <p className="font-mono text-sm text-muted-foreground text-center max-w-xs">
        4-4-4-4 box breathing: each side is 4 seconds. Used by Navy SEALs to stay calm under pressure.
      </p>

      {/* Box visualization */}
      <div className="relative h-44 w-44">
        {/* Box outline */}
        <div className={cn("absolute inset-0 rounded-2xl border-2 transition-all duration-500", boxColors[step])} />
        {/* Dot moving around the box */}
        <motion.div
          className="absolute h-5 w-5 rounded-full bg-primary shadow-lg"
          style={{ boxShadow: "0 0 12px hsl(var(--primary) / 0.8)" }}
          animate={active ? {
            x: [0, 120, 120, 0][step],
            y: [0, 0, 120, 120][step],
          } : { x: 0, y: 0 }}
          transition={{ duration: count, ease: "linear" }}
        />
        <div className="absolute inset-0 flex items-center justify-center flex-col gap-1">
          <span className="font-heading text-3xl font-bold text-foreground">{active ? count : "·"}</span>
          <span className="font-mono text-xs text-muted-foreground">{active ? SIDES[step] : "Ready"}</span>
        </div>
      </div>

      <div className="flex gap-3">
        <Button variant="outline" size="sm" onClick={reset} className="rounded-xl gap-2 font-mono text-xs">
          <RotateCcw className="h-3.5 w-3.5" /> Reset
        </Button>
        <Button size="sm" onClick={() => setActive((a) => !a)} className="rounded-xl gap-2 font-mono text-xs">
          <Play className="h-3.5 w-3.5" /> {active ? "Pause" : "Start"}
        </Button>
      </div>
    </div>
  );
}

/* ─── Relax Eyes ─── */
function RelaxEyes() {
  const [active, setActive] = useState(false);
  const [secondsLeft, setSecondsLeft] = useState(20);
  const DURATION = 20;

  useEffect(() => {
    if (!active) return;
    const id = setInterval(() => {
      setSecondsLeft((s) => {
        if (s <= 1) { clearInterval(id); setActive(false); return DURATION; }
        return s - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [active]);

  const start = () => { setSecondsLeft(DURATION); setActive(true); };

  return (
    <div className="flex flex-col items-center gap-8">
      <p className="font-mono text-sm text-muted-foreground text-center max-w-xs">
        The 20-20-20 rule: every 20 minutes, look at something 20 feet away for 20 seconds to reduce eye strain.
      </p>

      <div className="relative flex items-center justify-center">
        <motion.div
          className="h-36 w-36 rounded-full border-2 border-emerald-400/40 bg-emerald-400/5 flex flex-col items-center justify-center"
          animate={active ? { scale: [1, 1.05, 1], opacity: [0.8, 1, 0.8] } : {}}
          transition={{ duration: 2, repeat: Infinity }}
        >
          <Eye className="h-10 w-10 text-emerald-400 mb-2" />
          <span className="font-mono text-2xl font-bold text-foreground">{active ? secondsLeft : DURATION}</span>
          <span className="font-mono text-xs text-muted-foreground">seconds</span>
        </motion.div>
      </div>

      <Button
        size="sm"
        onClick={start}
        disabled={active}
        className="rounded-xl gap-2 font-mono text-xs bg-emerald-500/10 text-emerald-500 hover:bg-emerald-500 hover:text-white"
      >
        <Play className="h-3.5 w-3.5" />
        {active ? "Look away now…" : "Start 20s Timer"}
      </Button>
    </div>
  );
}

/* ─── Main MeditationCard ─── */
export function MeditationCard() {
  const [activity, setActivity] = useState<Activity>("deep");

  const tabs: { id: Activity; label: string; emoji: string }[] = [
    { id: "deep", label: "Deep Breathing", emoji: "🌬️" },
    { id: "box", label: "Box Breathing", emoji: "📦" },
    { id: "eyes", label: "Relax Eyes", emoji: "👁️" },
  ];

  return (
    <div className="space-y-8">
      {/* Tab selector */}
      <div className="flex flex-wrap justify-center gap-2">
        {tabs.map((t) => (
          <button
            key={t.id}
            onClick={() => setActivity(t.id)}
            className={cn(
              "rounded-xl px-4 py-2 font-mono text-xs transition-all duration-200 border",
              activity === t.id
                ? "bg-primary/15 border-primary/40 text-primary"
                : "bg-muted/10 border-border/30 text-muted-foreground hover:border-primary/20 hover:text-foreground"
            )}
          >
            {t.emoji} {t.label}
          </button>
        ))}
      </div>

      <AnimatePresence mode="wait">
        <motion.div
          key={activity}
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -10 }}
          transition={{ duration: 0.25 }}
        >
          {activity === "deep" && <DeepBreathing />}
          {activity === "box" && <BoxBreathing />}
