import { useState, useEffect, useRef } from "react";
import { Plus, MessageSquare, Bot, Clock, Trash2, SendHorizontal, Sparkles } from "lucide-react";
import { Client } from "@gradio/client";
import { DashboardLayout } from "@/components/DashboardLayout";
import { PageHeader } from "@/components/PageHeader";
import { Button } from "@/components/ui/button";
import { ChatBubble } from "@/components/codet/ChatBubble";
import { ChatInput } from "@/components/codet/ChatInput";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";

interface Message {
  role: "user" | "assistant";
  content: string;
}

interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  updatedAt: number;
}

export default function CodeT() {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const activeSession = sessions.find((s) => s.id === activeSessionId) || null;

  // Load history
  useEffect(() => {
    const saved = localStorage.getItem("codecraft_chat_history");
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) setActiveSessionId(parsed[0].id);
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history
  useEffect(() => {
    localStorage.setItem("codecraft_chat_history", JSON.stringify(sessions));
  }, [sessions]);

  // Scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [activeSession?.messages, isLoading]);

  const startNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: "New Chat",
      messages: [],
      updatedAt: Date.now(),
    };
    setSessions((prev) => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
  };

  const deleteSession = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setSessions((prev) => prev.filter((s) => s.id !== id));
    if (activeSessionId === id) setActiveSessionId(null);
  };

  const handleSendMessage = async (msg: string) => {
    if (!activeSessionId) {
      const newId = Date.now().toString();
      const newSession: ChatSession = {
        id: newId,
        title: msg.slice(0, 30) + (msg.length > 30 ? "..." : ""),
        messages: [{ role: "user", content: msg }],
        updatedAt: Date.now(),
      };
      setSessions((prev) => [newSession, ...prev]);
      setActiveSessionId(newId);
      processAIResponse(newId, msg, []);
    } else {
      const currentHistory = activeSession.messages.map(m => ({ role: m.role, content: m.content }));
      setSessions((prev) =>
        prev.map((s) =>
          s.id === activeSessionId
            ? {
                ...s,
                messages: [...s.messages, { role: "user", content: msg }],
                title: s.messages.length === 0 ? msg.slice(0, 30) + (msg.length > 30 ? "..." : "") : s.title,
                updatedAt: Date.now(),
              }
            : s
        )
      );
      processAIResponse(activeSessionId, msg, currentHistory);
    }
  };

  const processAIResponse = async (sessionId: string, userMsg: string, history: Message[]) => {
    setIsLoading(true);
    try {
      const client = await Client.connect("aaryanpethkar48/student-coding-assistant");
      const result = await client.predict("/respond", { 
        message: userMsg, 
        history: history,
      });

      const aiText = String((result as any).data || "I couldn't generate a response. Please try again.");

      setSessions((prev) =>
        prev.map((s) =>
          s.id === sessionId
            ? {
                ...s,
                messages: [...s.messages, { role: "assistant", content: aiText }],
              }
            : s
        )
      );
    } catch (err) {
      console.error("Gradio Error:", err);
      setSessions((prev) =>
        prev.map((s) =>
          s.id === sessionId
            ? {
                ...s,
                messages: [...s.messages, { role: "assistant", content: "Error: Could not connect to the AI model. Try again later." }],
              }
            : s
        )
      );
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <DashboardLayout>
      <div className="mx-auto max-w-7xl space-y-6 h-[calc(100vh-8rem)] flex flex-col">
        <PageHeader 
          title="CodeT AI Assistant" 
          description="Your professional coding companion. Natively integrated for history and speed." 
        />
        
        <div className="flex flex-1 overflow-hidden rounded-3xl border border-border/60 bg-card/40 backdrop-blur-xl shadow-2xl relative">
          
          {/* Top Gradient Accent */}
          <div className="absolute inset-x-0 top-0 h-1 bg-gradient-to-r from-primary to-primary/50 z-20" />

          {/* Left Sidebar (History) */}
          <div className="hidden md:flex w-72 flex-col border-r border-border/60 bg-muted/5 p-4 overflow-hidden">
            <Button 
              onClick={startNewChat}
              className="w-full justify-start gap-2 h-12 bg-primary/10 text-primary hover:bg-primary/20 hover:text-primary border border-primary/20 shadow-none font-semibold rounded-2xl transition-all"
            >
              <Plus className="h-5 w-5" /> New Chat
            </Button>

            <div className="mt-8 flex-1 overflow-y-auto space-y-6">
              <div>
                <div className="flex items-center gap-2 px-2 py-1.5 mb-2 opacity-50">
                  <Clock className="h-3.5 w-3.5" />
                  <span className="text-[10px] font-mono font-bold tracking-widest uppercase">
                    History
                  </span>
                </div>
                
                <div className="space-y-1">
                  {sessions.length === 0 && (
                    <div className="px-3 py-6 text-center">
                      <p className="text-xs text-muted-foreground italic">No chats yet</p>
                    </div>
                  )}
                  {sessions.map((session) => (
                    <button
                      key={session.id}
                      onClick={() => setActiveSessionId(session.id)}
                      className={cn(
                        "w-full text-left flex items-center justify-between gap-3 px-3 py-3 rounded-xl transition-all group relative",
                        activeSessionId === session.id 
                          ? "bg-primary/10 border border-primary/20 text-primary" 
                          : "hover:bg-muted/40 text-muted-foreground hover:text-foreground"
                      )}
                    >
                      <div className="flex items-center gap-2 overflow-hidden">
                        <MessageSquare className="h-4 w-4 shrink-0" />
                        <span className="text-sm font-mono truncate">
                          {session.title}
                        </span>
                      </div>
                      <button 
                        onClick={(e) => deleteSession(e, session.id)}
                        className="opacity-0 group-hover:opacity-100 hover:text-destructive transition-all p-1"
                      >
                        <Trash2 className="h-3 w-3" />
                      </button>
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="mt-auto pt-4 border-t border-border/40 flex items-center gap-3 px-2">
              <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary/10">
                <Sparkles className="h-5 w-5 text-primary" />
              </div>
              <div className="flex flex-col">
                <span className="text-xs font-bold leading-none">CodeT Engine</span>
                <span className="text-[10px] text-muted-foreground font-mono mt-1">Status: Operational</span>
              </div>
            </div>
          </div>

          {/* Main Chat Area */}
          <div className="flex-1 flex flex-col relative bg-background/20 overflow-hidden">
            {/* Messages Scroll Area */}
            <div 
              ref={scrollRef}
              className="flex-1 overflow-y-auto p-4 md:p-8 space-y-2 scroll-smooth"
            >
              {!activeSessionId ? (
                <div className="h-full flex flex-col items-center justify-center text-center max-w-sm mx-auto space-y-4">
                  <div className="h-16 w-16 rounded-3xl bg-primary/10 flex items-center justify-center mb-2">
                    <Bot className="h-10 w-10 text-primary" />
                  </div>
                  <h3 className="font-heading text-xl font-bold">How can I help you today?</h3>
                  <p className="font-mono text-sm text-muted-foreground leading-relaxed">
                    I'm your dedicated coding mentor. Ask me to debug code, explain logic, or brainstorm new project ideas.
                  </p>
                  <Button onClick={startNewChat} variant="outline" className="rounded-xl px-6 gap-2">
                    Start Your First Chat
                  </Button>
                </div>
              ) : activeSession?.messages.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center max-w-sm mx-auto">
                  <Sparkles className="h-12 w-12 text-primary/30 mb-4 animate-pulse" />
                  <p className="font-mono text-sm text-muted-foreground italic">
                    The floor is yours. Start typing to begin...
                  </p>
                </div>
              ) : (
                <div className="max-w-3xl mx-auto w-full">
                  <AnimatePresence mode="popLayout">
                    {activeSession?.messages.map((m, i) => (
                      <ChatBubble key={`${activeSession.id}-${i}`} role={m.role} content={m.content} />
                    ))}
                    {isLoading && (
                      <motion.div
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="flex gap-4 mb-6"
                      >
                        <div className="flex h-9 w-9 items-center justify-center rounded-xl bg-primary/10 border border-primary/20">
                          <Bot className="h-5 w-5 text-primary animate-pulse" />
                        </div>
                        <div className="glass rounded-2xl px-5 py-4 border border-border/50">
                          <div className="flex gap-1">
                            <span className="h-1.5 w-1.5 rounded-full bg-primary animate-bounce [animation-delay:-0.3s]" />
                            <span className="h-1.5 w-1.5 rounded-full bg-primary animate-bounce [animation-delay:-0.15s]" />
                            <span className="h-1.5 w-1.5 rounded-full bg-primary animate-bounce" />
                          </div>
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              )}
            </div>

            {/* Input Overlay at bottom */}
            <div className="p-4 md:p-6 border-t border-border/30 bg-background/40 backdrop-blur-md">
              <div className="max-w-3xl mx-auto">
                <ChatInput onSend={handleSendMessage} isLoading={isLoading} />
                <p className="text-[10px] text-center text-muted-foreground mt-3 font-mono opacity-50">
                  AI responses can be generated. Always double-check code for accuracy.
                </p>
              </div>
            </div>
          </div>

        </div>
      </div>
    </DashboardLayout>
  );
}

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Timer, Brain, Gamepad2, Sparkles, Youtube, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { TimerCard } from "@/components/focus/TimerCard";
import { MeditationCard } from "@/components/focus/MeditationCard";
import { GameCard } from "@/components/focus/GameCard";
import { QuoteCard } from "@/components/focus/QuoteCard";
import { VideoSection } from "@/components/focus/VideoSection";

const STORAGE_KEY = "focus_mode_last_tab";

type Tab = "timer" | "meditation" | "games" | "motivation" | "videos";

const TABS: { id: Tab; label: string; Icon: React.ElementType; color: string; desc: string }[] = [
  { id: "timer",      label: "Timer",      Icon: Timer,     color: "text-primary border-primary/40 bg-primary/10",          desc: "Focus session timer" },
  { id: "meditation", label: "Meditate",   Icon: Brain,     color: "text-violet-400 border-violet-400/40 bg-violet-400/10", desc: "Breathing exercises" },
  { id: "games",      label: "Games",      Icon: Gamepad2,  color: "text-sky-400 border-sky-400/40 bg-sky-400/10",          desc: "Light mental games" },
  { id: "motivation", label: "Motivation", Icon: Sparkles,  color: "text-amber-400 border-amber-400/40 bg-amber-400/10",    desc: "Inspiring quotes" },
  { id: "videos",     label: "Videos",     Icon: Youtube,   color: "text-rose-400 border-rose-400/40 bg-rose-400/10",       desc: "Focus & motivation" },
];

function loadTab(): Tab {
  try {
    const stored = localStorage.getItem(STORAGE_KEY) as Tab | null;
    if (stored && TABS.find((t) => t.id === stored)) return stored;
  } catch (_) {}
  return "timer";
}

export default function FocusMode() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<Tab>(loadTab);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, activeTab);
  }, [activeTab]);

  const current = TABS.find((t) => t.id === activeTab)!;

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Ambient glow */}
      <div className="pointer-events-none fixed inset-0 z-0">
        <div className="absolute top-0 left-1/4 h-96 w-96 rounded-full bg-primary/5 blur-3xl" />
        <div className="absolute bottom-1/4 right-1/4 h-72 w-72 rounded-full bg-violet-500/5 blur-3xl" />
      </div>

      <div className="relative z-10 flex flex-col min-h-screen p-4 md:p-8">
        {/* ── Header ── */}
        <div className="flex items-center justify-between mb-8">
          <div>
            <motion.h1
              initial={{ opacity: 0, x: -16 }}
              animate={{ opacity: 1, x: 0 }}
              className="font-heading text-2xl font-bold text-foreground flex items-center gap-3"
            >
              <div className="flex h-10 w-10 items-center justify-center rounded-2xl bg-primary/10 border border-primary/20">
                <Timer className="h-5 w-5 text-primary" />
              </div>
              Focus Mode
            </motion.h1>
            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.1 }}
              className="mt-1 font-mono text-xs text-muted-foreground pl-14"
            >
              Take a break. Reset your mind. Come back stronger.
            </motion.p>
          </div>
          <Button
            variant="outline"
            size="sm"
            onClick={() => navigate("/")}
            className="rounded-xl gap-2 font-mono text-xs border-rose-500/30 text-rose-400 hover:bg-rose-500/10"
          >
            <X className="h-3.5 w-3.5" />
            Exit Mode
          </Button>
        </div>

        {/* ── Tab Nav ── */}
        <motion.div
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.15 }}
          className="flex flex-wrap gap-2 mb-8"
        >
          {TABS.map((tab) => {
            const isActive = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={cn(
                  "flex items-center gap-2 rounded-2xl border px-4 py-2.5 font-mono text-xs font-medium transition-all duration-300",
                  isActive
                    ? tab.color
                    : "border-border/40 bg-muted/10 text-muted-foreground hover:border-border/70 hover:text-foreground hover:bg-muted/20"
                )}
              >
                <tab.Icon className="h-3.5 w-3.5" />
                {tab.label}
              </button>
            );
          })}
        </motion.div>

        {/* ── Content panel ── */}
        <motion.div
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="flex-1 rounded-3xl border border-border/50 bg-card/50 backdrop-blur-xl p-6 md:p-10"
        >
          {/* Panel header */}
          <div className="mb-8 flex items-center gap-3">
            <div className={cn("flex h-9 w-9 items-center justify-center rounded-xl border", current.color)}>
              <current.Icon className="h-4 w-4" />
            </div>
            <div>
              <h2 className="font-heading text-lg font-bold text-foreground">{current.label}</h2>
              <p className="font-mono text-xs text-muted-foreground">{current.desc}</p>
            </div>
          </div>

          {/* Tab content — animated */}
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -16 }}
              transition={{ duration: 0.3, ease: "easeOut" }}
            >
              {activeTab === "timer"      && <TimerCard />}
              {activeTab === "meditation" && <MeditationCard />}
              {activeTab === "games"      && <GameCard />}
              {activeTab === "motivation" && <QuoteCard />}
              {activeTab === "videos"     && <VideoSection />}
            </motion.div>
          </AnimatePresence>
        </motion.div>

        {/* Footer */}
        <p className="mt-6 text-center font-mono text-[10px] text-muted-foreground/40">
          Focus Mode · Your last tab is restored automatically
        </p>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/DashboardLayout";
import { PageHeader } from "@/components/PageHeader";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { 
  Flame, 
  Trophy, 
  UserPlus, 
  Search, 
  Loader2, 
  CheckCircle2, 
  Target, 
  Medal, 
  LayoutGrid, 
  List 
} from "lucide-react";
import { cn } from "@/lib/utils";
import { fetchFriends, searchUsers, addFriend, FriendUser } from "@/services/friends";
import { toast } from "sonner";
import { Link } from "react-router-dom";
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";

function initials(name: string) {
  return name
    .split(/[\s_]+/)
    .map((p) => p[0])
    .join("")
    .slice(0, 2)
    .toUpperCase();
}

export default function Friends() {
  const [search, setSearch] = useState("");
  const [viewMode, setViewMode] = useState<"grid" | "leaderboard">("grid");
  const queryClient = useQueryClient();

  // 1. Fetch current friends
  const { data: friends, isLoading: isLoadingFriends } = useQuery({
    queryKey: ["friends"],
    queryFn: fetchFriends,
  });

  // 2. Search users globally
  const { data: searchResults, isFetching: isSearching } = useQuery({
    queryKey: ["users-search", search],
    queryFn: () => searchUsers(search),
    enabled: search.length >= 2,
    staleTime: 500,
  });

  // 3. Add friend mutation
  const addMutation = useMutation({
    mutationFn: addFriend,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["friends"] });
      queryClient.invalidateQueries({ queryKey: ["users-search"] });
      toast.success("Friend added successfully!");
    },
    onError: (error: any) => {
      toast.error(error.response?.data?.message || "Failed to add friend");
    }
  });

  const filteredFriends = friends?.filter((f) => 
    f.username.toLowerCase().includes(search.toLowerCase())
  ) || [];

  // Exclude people already in friends from search results
  const globalResults = searchResults?.filter(
    (u) => !friends?.some((f) => f._id === u._id)
  ) || [];

  return (
    <DashboardLayout>
      <div className="mx-auto max-w-6xl space-y-8 pb-20">
        <PageHeader
          title="Study Circle"
          description="Find other members and track your coding streaks together."
        />

        {/* Search Bar */}
        <div className="max-w-xl relative group">
          <div className="absolute left-4 top-1/2 -translate-y-1/2 text-muted-foreground group-focus-within:text-primary transition-colors">
            {isSearching ? <Loader2 className="h-4 w-4 animate-spin" /> : <Search className="h-4 w-4" />}
          </div>
          <input
            type="text"
            placeholder="Search by name or email..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full rounded-2xl border border-border/60 bg-card/40 pl-11 pr-4 py-3 font-mono text-sm text-foreground backdrop-blur-sm transition-all focus:bg-card/80 focus:ring-2 focus:ring-primary/20 outline-none border-dashed"
          />
        </div>

        {/* Global Search Results Section */}
        <AnimatePresence>
          {search.length >= 2 && globalResults.length > 0 && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              className="space-y-4 pt-4 border-t border-dashed border-border/40"
            >
              <h3 className="font-heading text-xs font-bold uppercase tracking-widest text-primary/80 px-1">Global Results</h3>
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
                {globalResults.map((user) => (
                  <UserCard 
                    key={user._id} 
                    user={user} 
                    isFriend={false} 
                    onAdd={() => addMutation.mutate(user._id)}
                    isAdding={addMutation.isPending && addMutation.variables === user._id}
                  />
                ))}
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Content Section with Tabs */}
        <Tabs value={viewMode} onValueChange={(v) => setViewMode(v as any)} className="space-y-6">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 px-1">
            <h3 className="font-heading text-xs font-bold uppercase tracking-widest text-muted-foreground flex items-center gap-2">
              Your Circle
              <span className="font-mono text-[10px] text-muted-foreground/60 normal-case tracking-normal">({friends?.length || 0} members)</span>
            </h3>
            
            <TabsList className="bg-muted/30 border border-border/40 p-1 rounded-xl h-10 w-fit">
              <TabsTrigger 
                value="grid" 
                className="rounded-lg px-3 text-[10px] font-bold uppercase tracking-wider data-[state=active]:bg-primary/20 data-[state=active]:text-primary"
              >
                <LayoutGrid className="h-3.5 w-3.5 mr-2" />
                Grid
              </TabsTrigger>
              <TabsTrigger 
                value="leaderboard" 
                className="rounded-lg px-3 text-[10px] font-bold uppercase tracking-wider data-[state=active]:bg-primary/20 data-[state=active]:text-primary"
              >
                <List className="h-3.5 w-3.5 mr-2" />
                Leaderboard
              </TabsTrigger>
            </TabsList>
          </div>

          <TabsContent value="grid" className="mt-0 space-y-4 outline-none">
            {isLoadingFriends ? (
              <div className="flex h-40 items-center justify-center rounded-2xl border border-dashed border-border/40 bg-muted/5">
                <Loader2 className="h-6 w-6 animate-spin text-primary/40" />
              </div>
            ) : friends && friends.length > 0 ? (
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
                {(search.length < 2 ? friends : filteredFriends).map((user, i) => (
                  <UserCard key={user._id} user={user} isFriend={true} delay={i * 0.05} />
                ))}
              </div>
            ) : (
              <EmptyCircle />
            )}
          </TabsContent>

          <TabsContent value="leaderboard" className="mt-0 outline-none">
            {isLoadingFriends ? (
              <div className="space-y-4">
                {Array.from({ length: 5 }).map((_, i) => (
                  <div key={i} className="h-16 w-full animate-pulse rounded-xl bg-muted/20" />
                ))}
              </div>
            ) : friends && friends.length > 0 ? (
              <FriendsLeaderboard users={search.length < 2 ? friends : filteredFriends} />
            ) : (
              <EmptyCircle />
            )}
          </TabsContent>
        </Tabs>
      </div>
    </DashboardLayout>
  );
}

function EmptyCircle() {
  return (
    <div className="rounded-3xl border border-dashed border-border/60 bg-muted/5 px-4 py-16 text-center">
      <div className="mx-auto w-12 h-12 rounded-2xl bg-primary/5 flex items-center justify-center mb-4 border border-primary/10">
        <Search className="h-6 w-6 text-primary/40" />
      </div>
      <p className="font-mono text-sm text-foreground font-bold">Your circle is empty</p>
      <p className="mt-2 font-mono text-[11px] text-muted-foreground max-w-xs mx-auto">
        Search for your friends by their name and add them to compare streaks.
      </p>
    </div>
  );
}

function FriendsLeaderboard({ users }: { users: FriendUser[] }) {
  const getRankIcon = (rank: number) => {
    switch (rank) {
      case 1: return <Trophy className="h-5 w-5 text-yellow-400 drop-shadow-[0_0_8px_rgba(250,204,21,0.5)]" />;
      case 2: return <Medal className="h-5 w-5 text-slate-300 drop-shadow-[0_0_8px_rgba(203,213,225,0.5)]" />;
      case 3: return <Medal className="h-5 w-5 text-amber-600 drop-shadow-[0_0_8px_rgba(180,83,9,0.5)]" />;
      default: return <span className="text-muted-foreground font-mono text-xs font-black">{rank}</span>;
    }
  };

  const getRankStyle = (rank: number) => {
    switch (rank) {
      case 1: return "bg-yellow-400/5 hover:bg-yellow-400/10 border-yellow-400/20";
      case 2: return "bg-slate-300/5 hover:bg-slate-300/10 border-slate-300/20";
      case 3: return "bg-amber-600/5 hover:bg-amber-600/10 border-amber-600/20";
      default: return "hover:bg-muted/30";
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0, scale: 0.98 }}
      animate={{ opacity: 1, scale: 1 }}
      className="rounded-[2rem] border border-foreground/10 bg-card/30 backdrop-blur-3xl overflow-hidden shadow-2xl premium-border"
    >
      <Table>
        <TableHeader className="bg-muted/10">
          <TableRow className="hover:bg-transparent border-foreground/5 uppercase tracking-[0.2em] font-mono text-[9px]">
            <TableHead className="w-[80px] text-center font-black">Rank</TableHead>
            <TableHead className="font-black">Coder</TableHead>
            <TableHead className="text-right font-black">Solved</TableHead>
            <TableHead className="text-right font-black">Streak</TableHead>
            <TableHead className="text-right hidden sm:table-cell font-black pr-6">Activity</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {users.map((user, index) => (
            <TableRow 
              key={user._id} 
              className={cn(
                "group border-foreground/5 transition-all duration-500",
                getRankStyle(index + 1),
                user.isMe && "bg-primary/5 hover:bg-primary/10 border-l-2 border-l-primary"
              )}
            >
              <TableCell className="text-center">
                <div className="flex items-center justify-center transition-transform duration-500 group-hover:scale-110">
                  {getRankIcon(index + 1)}
                </div>
              </TableCell>
              <TableCell>
                <div className="flex items-center gap-3">
                  <Link to={`/dashboard/${user._id}`} className="flex items-center gap-3 hover:opacity-80 transition-opacity py-1">
                    <Avatar className="h-10 w-10 rounded-xl border border-foreground/5 shadow-lg transition-transform duration-500 group-hover:scale-105">
                      {user.profileImage && <AvatarImage src={user.profileImage} className="object-cover" />}
                      <AvatarFallback className="bg-gradient-to-br from-primary/20 to-primary/5 text-primary uppercase font-black text-[10px]">
                        {initials(user.username)}
                      </AvatarFallback>
                    </Avatar>
                    <div className="flex flex-col gap-0.5">
                      <span className="font-black text-sm text-foreground group-hover:text-primary transition-colors flex items-center gap-2">
                        {user.username}
                        {user.isMe && <Badge className="text-[8px] h-4 py-0 px-1.5 bg-primary/10 text-primary border-primary/20 font-black tracking-widest uppercase">YOU</Badge>}
                      </span>
                      <span className="text-[10px] text-muted-foreground font-mono hidden sm:block uppercase tracking-tighter opacity-60 font-black">
                        {index === 0 ? "Circuit Leader" : index === 1 ? "Elite" : index === 2 ? "Advanced" : "Rising"}
                      </span>
                    </div>
                  </Link>
                </div>
              </TableCell>
              <TableCell className="text-right">
                <div className="flex items-center justify-end gap-2 pr-2">
                  <Target className="h-3.5 w-3.5 text-primary/50" />
                  <span className="font-heading font-black text-base tabular-nums transition-all group-hover:scale-110 group-hover:text-primary">{user.problemsSolved}</span>
                </div>
              </TableCell>
              <TableCell className="text-right">
                <div className="flex items-center justify-end gap-2 pr-2">
                  <div className={cn(
                    "flex items-center gap-1.5 px-2 py-0.5 rounded-xl border text-[10px] font-black",
                    user.streak > 0 ? "bg-leetcode/10 text-leetcode border-leetcode/20" : "text-muted-foreground/30 border-foreground/5"
                  )}>
                    <Flame className="h-3 w-3" />
                    <span className="font-mono tabular-nums">{user.streak}d</span>
                  </div>
                </div>
              </TableCell>
              <TableCell className="text-right hidden sm:table-cell pr-6">
                <div className="flex items-center justify-end gap-1.5">
                  {Object.entries(user.platformStats || {}).map(([platform, count]) => (
                    <Badge 
                      key={platform} 
                      variant="outline" 
                      className="bg-foreground/5 text-[9px] font-black font-mono py-0 px-1.5 border-foreground/5 group-hover:border-primary/20 transition-colors"
                    >
                      {count as number}
                    </Badge>
                  ))}
                </div>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </motion.div>
  );
}

function UserCard({ 
  user, 
  isFriend, 
  onAdd, 
  isAdding,
  delay = 0 
}: { 
  user: any; 
  isFriend: boolean; 
  onAdd?: () => void;
  isAdding?: boolean;
  delay?: number
}) {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.9, y: 20 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      transition={{ delay, duration: 0.6, ease: [0.23, 1, 0.32, 1] }}
      className="h-full"
    >
      <Card className="h-full rounded-[2rem] border border-foreground/10 bg-card/30 backdrop-blur-2xl transition-all duration-500 hover:-translate-y-2 hover:shadow-2xl hover:shadow-primary/5 hover:border-primary/20 group tilt-card premium-border overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-br from-foreground/[0.04] to-transparent pointer-events-none" />
        
        <CardHeader className="flex flex-row items-center gap-4 space-y-0 pb-4 relative z-10">
          <Link to={`/dashboard/${user._id}`} className="shrink-0 hover:opacity-80 transition-opacity">
            <Avatar className="h-14 w-14 rounded-2xl border-2 border-foreground/10 shadow-2xl transition-all duration-500 group-hover:border-primary/50 group-hover:scale-105 group-hover:shadow-primary/20">
              {user.profileImage && <AvatarImage src={user.profileImage} className="object-cover" />}
              <AvatarFallback className="rounded-2xl bg-gradient-to-br from-primary/20 to-primary/5 font-black text-sm text-primary uppercase">
                {initials(user.username)}
              </AvatarFallback>
            </Avatar>
          </Link>
          
          <div className="min-w-0 flex-1">
            <Link to={`/dashboard/${user._id}`} className="block group/link">
              <h4 className="truncate font-heading text-base font-black text-foreground group-hover:text-primary transition-colors tracking-tight">
                {user.username}
              </h4>
            </Link>
            <p className="truncate font-mono text-[10px] text-muted-foreground/60 uppercase tracking-tighter font-black">{user.email}</p>
          </div>

          {!isFriend && (
            <button
              onClick={onAdd}
              disabled={isAdding}
              className="h-11 w-11 shrink-0 rounded-2xl bg-primary/10 border border-primary/20 flex items-center justify-center text-primary hover:bg-primary hover:text-white transition-all duration-300 shadow-lg shadow-primary/10 hover:shadow-primary/30 active:scale-90"
            >
              {isAdding ? <Loader2 className="h-5 w-5 animate-spin" /> : <UserPlus className="h-5 w-5" />}
            </button>
          )}
          {isFriend && (
            <div className="h-2 w-2 rounded-full bg-green-400 shadow-[0_0_10px_rgba(74,222,128,0.8)] pulse-indicator" title="Connected" />
          )}
        </CardHeader>

        <CardContent className="pt-2 relative z-10">
          <div className="grid grid-cols-2 gap-3 rounded-2xl border border-foreground/5 bg-foreground/[0.03] p-4 transition-all duration-500 group-hover:bg-foreground/[0.05] group-hover:border-foreground/10">
            <div className="flex items-center gap-3">
              <div className="w-9 h-9 rounded-xl bg-orange-400/10 border border-orange-400/20 flex items-center justify-center shadow-inner">
                <Flame className="h-4 w-4 text-orange-400" />
              </div>
              <div>
                <p className="font-mono text-[9px] uppercase tracking-widest text-muted-foreground font-black opacity-60">Streak</p>
                <p className="font-mono text-xs font-black text-foreground tabular-nums">{user.streak || 0}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="w-9 h-9 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center shadow-inner">
                <Trophy className="h-4 w-4 text-primary" />
              </div>
              <div>
                <p className="font-mono text-[9px] uppercase tracking-widest text-muted-foreground font-black opacity-60">Solved</p>
                <p className="font-mono text-xs font-black text-foreground tabular-nums">{user.problemsSolved || 0}</p>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
    </motion.div>
  );
}

import { DashboardLayout } from "@/components/DashboardLayout";
import { PageHeader } from "@/components/PageHeader";
import { useQuery } from "@tanstack/react-query";
import { getLeaderboard } from "@/services/user";
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from "@/components/ui/table";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Trophy, Flame, Target, Medal, Sparkles } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { Link } from "react-router-dom";
import { cn } from "@/lib/utils";

export default function Leaderboard() {
  const { data: users, isLoading } = useQuery({
    queryKey: ["leaderboard"],
    queryFn: getLeaderboard,
    refetchInterval: 30000, 
  });

  const getRankIcon = (rank: number) => {
    switch (rank) {
      case 1: return <Trophy className="h-6 w-6 text-yellow-400 drop-shadow-[0_0_8px_rgba(250,204,21,0.5)]" />;
      case 2: return <Medal className="h-6 w-6 text-slate-300 drop-shadow-[0_0_8px_rgba(203,213,225,0.5)]" />;
      case 3: return <Medal className="h-6 w-6 text-amber-600 drop-shadow-[0_0_8px_rgba(180,83,9,0.5)]" />;
      default: return <span className="text-muted-foreground font-mono font-black text-sm">{rank}</span>;
    }
  };

  const getRankStyle = (rank: number) => {
    switch (rank) {
      case 1: return "bg-yellow-400/5 hover:bg-yellow-400/10 border-yellow-400/20";
      case 2: return "bg-slate-300/5 hover:bg-slate-300/10 border-slate-300/20";
      case 3: return "bg-amber-600/5 hover:bg-amber-600/10 border-amber-600/20";
      default: return "hover:bg-muted/30";
    }
  };

  const getRankLabel = (index: number) => {
    if (index === 0) return "Grandmaster";
    if (index === 1) return "Master";
    if (index === 2) return "Expert";
    if (index < 10) return "Challenger";
    return "Rookie";
  };

  return (
    <DashboardLayout>
      <div className="mx-auto max-w-6xl space-y-10 pb-20">
        <PageHeader 
          title="Global Leaderboard" 
          description="Competitive programming rankings based on consistency, speed, and platform performance." 
        />

        {isLoading ? (
          <div className="space-y-4">
            {Array.from({ length: 8 }).map((_, i) => (
              <div key={i} className="h-20 w-full animate-shimmer rounded-3xl bg-muted/10 border border-foreground/5" />
            ))}
          </div>
        ) : (
          <motion.div 
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.7, ease: [0.23, 1, 0.32, 1] }}
            className="rounded-[2.5rem] border border-foreground/10 bg-card/30 backdrop-blur-3xl overflow-hidden shadow-2xl premium-border"
          >
            <div className="absolute inset-0 bg-gradient-to-b from-foreground/[0.02] to-transparent pointer-events-none" />
            
            <Table>
              <TableHeader className="bg-muted/10">
                <TableRow className="hover:bg-transparent border-foreground/5 uppercase tracking-[0.2em] font-mono text-[10px]">
                  <TableHead className="w-[100px] text-center font-black">Rank</TableHead>
                  <TableHead className="font-black">Coder</TableHead>
                  <TableHead className="text-right font-black">Solved</TableHead>
                  <TableHead className="text-right font-black">Streak</TableHead>
                  <TableHead className="text-right font-black pr-8">Platforms</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                <AnimatePresence mode="popLayout">
                  {users?.map((user, index) => (
                    <motion.tr
                      layout
                      key={user._id}
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: index * 0.05 }}
                      className={cn(
                        "group border-foreground/5 transition-all duration-500 hover:-translate-y-0.5",
                        getRankStyle(index + 1)
                      )}
                    >
                      <TableCell className="text-center">
                        <div className="flex items-center justify-center transition-transform duration-500 group-hover:scale-110">
                          {getRankIcon(index + 1)}
                        </div>
                      </TableCell>
                      <TableCell>
                        <Link 
                          to={`/dashboard/${user._id}`} 
                          className="flex items-center gap-4 group/user py-2"
                        >
                          <div className="relative">
                            <Avatar className="h-12 w-12 rounded-2xl border-2 border-foreground/5 shadow-xl transition-all duration-500 group-hover/user:border-primary/50 group-hover/user:scale-105 group-hover/user:shadow-primary/20">
                              <AvatarImage src={(user as any).profileImage} className="object-cover" />
                              <AvatarFallback className="bg-gradient-to-br from-primary/20 to-primary/5 text-primary uppercase font-black text-xs">
                                {user.username.substring(0, 2)}
                              </AvatarFallback>
                            </Avatar>
                            {index < 3 && (
                              <div className="absolute -top-1.5 -right-1.5 h-5 w-5 bg-background rounded-full border border-foreground/10 flex items-center justify-center shadow-lg">
                                <Sparkles className={cn("h-2.5 w-2.5", index === 0 ? "text-yellow-400" : index === 1 ? "text-slate-300" : "text-amber-600")} />
                              </div>
