                                variant="outline" 
                                className="bg-foreground/5 text-[9px] font-black font-mono py-0.5 px-2.5 border-foreground/10 group-hover:bg-primary/20 group-hover:text-primary group-hover:border-primary/30 transition-all duration-300"
                              >
                                {count as number}
                              </Badge>
                            </div>
                          ))}
                        </div>
                      </TableCell>
                    </motion.tr>
                  ))}
                </AnimatePresence>
              </TableBody>
            </Table>
            
            {(!users || users.length === 0) && (
              <div className="py-24 text-center group/no-results">
                <div className="h-16 w-16 bg-muted/10 rounded-[2rem] flex items-center justify-center mx-auto mb-6 border border-foreground/5 transition-transform group-hover/no-results:scale-110 duration-700">
                  <Target className="h-8 w-8 text-muted-foreground/20" />
                </div>
                <h3 className="font-heading font-black text-lg text-foreground mb-2 tracking-tight">The Arena is Empty</h3>
                <p className="text-muted-foreground font-mono text-xs uppercase tracking-widest max-w-xs mx-auto opacity-60">Be the first to claim a spot on the global standings.</p>
              </div>
            )}
            
            {/* Animated background flare */}
            <div className="absolute -bottom-20 -left-20 h-64 w-64 bg-primary/10 blur-[100px] rounded-full pointer-events-none" />
            <div className="absolute -top-20 -right-20 h-64 w-64 bg-codeforces/10 blur-[100px] rounded-full pointer-events-none" />
          </motion.div>
        )}
      </div>
    </DashboardLayout>
  );
}

import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { login, googleLogin } from "@/services/auth";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { GoogleLogin } from "@react-oauth/google";

export default function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    setSubmitting(true);
    setError(null);
    try {
      const data = (await login({ email, password })) as any;
      if (data && data.user) {
        const safeUser = {
          username: data?.user?.username || "User",
          email: data?.user?.email || ""
        };
        localStorage.setItem("user", JSON.stringify(safeUser));
        localStorage.setItem("token", data.token || "auth-token");
      }
      navigate("/");
    } catch (err: any) {
      setError(err?.response?.data?.message || "Login failed");
    } finally {
      setSubmitting(false);
    }
  }

  const handleMockGoogleLogin = () => {
    const user = {
      username: "Sahil",
      email: "sahil@gmail.com"
    };
    localStorage.setItem("user", JSON.stringify(user));
    localStorage.setItem("token", "mock-google-oauth-token");
    navigate("/");
  };

  return (
    <div className="min-h-screen bg-[#050505] text-gray-100 flex items-center justify-center p-6">
      <form
        onSubmit={onSubmit}
        className="w-full max-w-md rounded-2xl border border-white/10 bg-[#0a0a0a] shadow-2xl p-8 space-y-5"
      >
        <div>
          <h1 className="text-2xl font-heading font-bold text-white tracking-tight">Welcome Back</h1>
          <p className="text-xs font-mono text-gray-400 mt-1.5">Sign in to your CodeTrack account</p>
        </div>

        <div className="space-y-1.5">
          <label className="text-[10px] font-mono uppercase tracking-widest text-gray-500">Email</label>
          <Input
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            type="email"
            required
            className="rounded-xl border-white/10 bg-white/5 text-white placeholder:text-gray-500 focus-visible:ring-primary/50"
          />
        </div>

        <div className="space-y-1.5">
          <label className="text-[10px] font-mono uppercase tracking-widest text-gray-500">Password</label>
          <Input
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            type="password"
            required
            className="rounded-xl border-white/10 bg-white/5 text-white placeholder:text-gray-500 focus-visible:ring-primary/50"
          />
        </div>

        {error && <p className="text-xs font-mono text-red-400">{error}</p>}

        <Button type="submit" className="w-full rounded-xl font-mono text-xs bg-white text-black hover:bg-gray-200 transition-all font-bold mt-2" disabled={submitting}>
          {submitting ? "Signing in…" : "Sign in"}
        </Button>

        <div className="relative my-5">
          <div className="absolute inset-0 flex items-center">
            <span className="w-full border-t border-white/10" />
          </div>
          <div className="relative flex justify-center text-[10px] tracking-widest uppercase">
            <span className="bg-[#0a0a0a] px-3 text-gray-500 font-mono">Or continue with</span>
          </div>
        </div>

        <div className="flex justify-center w-full">
          <GoogleLogin
            onSuccess={async (credentialResponse) => {
              console.log("Login success", credentialResponse);
              try {
                const data = await googleLogin(credentialResponse.credential!);
                localStorage.setItem("token", data.token);
                localStorage.setItem("user", JSON.stringify(data.user));
                window.location.href = "/";
              } catch (err) {
                console.error("Google login failed:", err);
                setError("Failed to sync with account. Please try again.");
              }
            }}
            onError={() => {
              console.log("Login Failed");
              setError("Google login failed");
            }}
            theme="filled_black"
            shape="pill"
            text="continue_with"
            size="large"
            width="100%"
          />
        </div>

        <p className="text-xs font-mono text-gray-500 text-center mt-6">
          New here?{" "}
          <Link to="/register" className="text-primary hover:text-primary/80 transition-colors font-medium hover:underline">
            Create an account
          </Link>
        </p>
      </form>
    </div>
  );
}

import { useState, useMemo } from "react";
import { DashboardLayout } from "@/components/DashboardLayout";
import { PageHeader } from "@/components/PageHeader";
import { FiltersBar } from "@/components/problems/FiltersBar";
import { ProblemCard, Problem } from "@/components/problems/ProblemCard";
import problemsData from "@/data/problems.json";
import { motion, AnimatePresence } from "framer-motion";

export default function Problems() {
  const [searchTerm, setSearchTerm] = useState("");
  const [platform, setPlatform] = useState("all");
  const [difficulty, setDifficulty] = useState("all");

  const typedProblemsData = problemsData as Problem[];

  const filteredProblems = useMemo(() => {
    return typedProblemsData.filter((prob) => {
      const matchesSearch = prob.title.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesPlatform = platform === "all" || prob.platform === platform;
      const matchesDifficulty = difficulty === "all" || prob.difficulty === difficulty;
      return matchesSearch && matchesPlatform && matchesDifficulty;
    });
  }, [searchTerm, platform, difficulty]);

  return (
    <DashboardLayout>
      <div className="mx-auto max-w-7xl space-y-8 animate-in fade-in duration-500">
        <PageHeader 
          title="Problems" 
          description="Level up your skills by solving curated challenges from top coding platforms." 
        />

        <div className="glass rounded-3xl p-6 space-y-6">
          <FiltersBar
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            platform={platform}
            setPlatform={setPlatform}
            difficulty={difficulty}
            setDifficulty={setDifficulty}
          />

          <div className="pt-4">
            {filteredProblems.length === 0 ? (
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="flex flex-col items-center justify-center py-20 text-center space-y-4"
              >
                <div className="h-16 w-16 rounded-2xl bg-muted/20 flex items-center justify-center text-muted-foreground">
                  <span className="text-2xl">🔍</span>
                </div>
                <div>
                  <h3 className="text-xl font-heading font-semibold text-foreground">No problems found</h3>
                  <p className="text-muted-foreground max-w-xs mx-auto mt-2">
                    Try adjusting your filters or search term to find what you're looking for.
                  </p>
                </div>
              </motion.div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <AnimatePresence mode="popLayout">
                  {filteredProblems.map((prob) => (
                    <ProblemCard key={prob.id} problem={prob} />
                  ))}
                </AnimatePresence>
              </div>
            )}
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
}

import { useQuery } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/DashboardLayout";
import { PageHeader } from "@/components/PageHeader";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { fetchProfile, fetchUserProfile } from "@/services/user";
import { useState, useRef, useEffect } from "react";
import { Camera, User, Upload, X, Check, HelpCircle } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { toast } from "sonner";

import { useParams, useNavigate } from "react-router-dom";
import { WebsiteTour } from "@/components/WebsiteTour";

export default function Profile() {
  const { userId } = useParams();
  const navigate = useNavigate();
  const userStr = localStorage.getItem("user");
  const localUser = userStr ? JSON.parse(userStr) : null;
  const isOwnProfile = !userId || userId === localUser?._id;
  const [showTour, setShowTour] = useState(false);

  const [profileImage, setProfileImage] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const { data: user, isLoading, isError } = useQuery({
    queryKey: ["profile", userId],
    queryFn: () => userId ? fetchUserProfile(userId) : fetchProfile(),
    initialData: isOwnProfile ? localUser : undefined,
  });

  useEffect(() => {
    if (isOwnProfile) {
      setProfileImage(localStorage.getItem("profile-photo") || user?.profileImage || localUser?.profileImage || null);
    } else if (user?.profileImage) {
      setProfileImage(user.profileImage);
    }
  }, [user, userId, isOwnProfile]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        toast.error("Image too large. Please select a file under 2MB.");
        return;
      }

      setIsUploading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        localStorage.setItem("profile-photo", base64String);
        setProfileImage(base64String);
        setIsUploading(false);
        toast.success("Profile photo updated successfully!");
        window.dispatchEvent(new Event("profile-photo-updated"));
      };
      reader.readAsDataURL(file);
    }
  };

  const removePhoto = () => {
    localStorage.removeItem("profile-photo");
    setProfileImage(user?.profileImage || null);
    toast.success("Profile photo removed.");
    window.dispatchEvent(new Event("profile-photo-updated"));
  };

  if (!user || (!user.username && isLoading)) {
    return <div className="p-10 text-white font-mono">Loading...</div>;
  }

  return (
    <DashboardLayout>
      <div className="mx-auto max-w-5xl space-y-8">
        <PageHeader 
          title={isOwnProfile ? "Your Profile" : `${user?.username}'s Dashboard`} 
          description={isOwnProfile ? "Manage your account and view your stats." : `Viewing ${user?.username}'s coding stats and progress.`} 
        />

        {isLoading && !user ? (
          <div className="rounded-2xl border border-border/60 bg-card/60 backdrop-blur-xl p-6 text-center font-mono text-sm text-muted-foreground">
            Loading profile…
          </div>
        ) : isError ? (
          <div className="rounded-2xl border border-border/60 bg-card/60 backdrop-blur-xl p-6 text-center font-mono text-sm text-muted-foreground">
            Couldn’t load profile. Please login again.
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-6 lg:grid-cols-12">
            {/* Avatar Section */}
            <Card className="lg:col-span-4 rounded-3xl border-border/60 bg-card/60 backdrop-blur-xl overflow-hidden shadow-xl border-dashed">
              <CardContent className="pt-8 pb-6 flex flex-col items-center">
                <div className="relative group">
                  <motion.div 
                    whileHover={{ scale: 1.02 }}
                    className="h-32 w-32 rounded-3xl bg-gradient-to-br from-primary/20 to-primary/5 border-2 border-primary/20 flex items-center justify-center overflow-hidden shadow-2xl relative"
                  >
                    {profileImage ? (
                      <img src={profileImage} alt="Profile" className="h-full w-full object-cover" />
                    ) : (
                      <div className="flex flex-col items-center gap-1 text-muted-foreground/60">
                        <User className="h-12 w-12" />
                        <span className="text-[10px] font-mono uppercase tracking-tighter">No Photo</span>
                      </div>
                    )}
                    
                    {isUploading && (
                      <div className="absolute inset-0 bg-background/60 backdrop-blur-sm flex items-center justify-center">
                        <div className="h-5 w-5 border-2 border-primary border-t-transparent rounded-full animate-spin" />
                      </div>
                    )}

                    {isOwnProfile && (
                      <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center cursor-pointer backdrop-blur-[2px]"
                      >
                        <Camera className="h-8 w-8 text-white" />
                      </div>
                    )}
                  </motion.div>
                  
                  {isOwnProfile && profileImage && profileImage !== user?.profileImage && (
                    <button 
                      onClick={removePhoto}
                      className="absolute -top-2 -right-2 h-7 w-7 rounded-full bg-destructive text-destructive-foreground shadow-lg flex items-center justify-center hover:scale-110 transition-transform z-10"
                    >
                      <X className="h-4 w-4" />
                    </button>
                  )}
                </div>

                <div className="mt-6 text-center">
                  <h3 className="text-lg font-heading font-bold text-foreground capitalize">{user.username}</h3>
                  <p className="text-xs text-muted-foreground font-mono mt-0.5">{user.email}</p>
                </div>

                {isOwnProfile && (
                  <>
                    <input 
                      type="file" 
                      ref={fileInputRef} 
                      className="hidden" 
                      accept="image/*" 
                      onChange={handleFileChange} 
                    />
                    
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className="mt-6 w-full flex items-center justify-center gap-2 bg-primary/10 hover:bg-primary/20 text-primary px-4 py-2.5 rounded-xl border border-primary/20 text-xs font-bold transition-all"
                    >
                      <Upload className="h-3.5 w-3.5" />
                      {profileImage ? "Change Photo" : "Upload Photo"}
                    </button>

                    <button 
                      onClick={() => {
                        localStorage.removeItem("codetrack_tour_done");
                        navigate("/");
                      }}
                      className="mt-3 w-full flex items-center justify-center gap-2 bg-muted/20 hover:bg-muted/30 text-muted-foreground px-4 py-2.5 rounded-xl border border-border/40 text-xs font-bold transition-all"
                    >
                      <HelpCircle className="h-3.5 w-3.5" />
                      Take Website Tour
                    </button>
                  </>
                )}
              </CardContent>
            </Card>

            {/* Account Details */}
            <div className="lg:col-span-8 space-y-6">
              <Card className="rounded-3xl border-border/60 bg-card/60 backdrop-blur-xl shadow-lg">
                <CardHeader>
                  <CardTitle className="font-heading text-sm font-bold uppercase tracking-widest text-muted-foreground">Account Stats</CardTitle>
                </CardHeader>
                <CardContent className="grid gap-4 sm:grid-cols-2">
                  <Info label="Username" value={user?.username || "Admin"} />
                  <Info label="Email Address" value={user?.email || ""} />
                  <Info label="Current Streak" value={`${user?.streak || 0} days`} />
                  <Info label="Problems Solved" value={`${user?.problemsSolved || 0}`} />
                </CardContent>
              </Card>

              <Card className="rounded-3xl border-border/60 bg-card/60 backdrop-blur-xl shadow-lg">
                <CardHeader>
                  <CardTitle className="font-heading text-sm font-bold uppercase tracking-widest text-muted-foreground">Platform Activity</CardTitle>
                </CardHeader>
                <CardContent className="grid gap-4 sm:grid-cols-3">
                  <Info label="LeetCode" value={`${user?.platformStats?.leetcode || 0}`} />
                  <Info label="Codeforces" value={`${user?.platformStats?.codeforces || 0}`} />
                  <Info label="CodeChef" value={`${user?.platformStats?.codechef || 0}`} />
                </CardContent>
              </Card>
            </div>
          </div>
        )}
      </div>
    </DashboardLayout>
  );
}

function Info({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-xl border border-border/40 bg-muted/10 p-3">
      <p className="text-[10px] font-mono uppercase tracking-widest text-muted-foreground">{label}</p>
      <p className="mt-1 font-mono text-sm font-semibold text-foreground truncate">{value}</p>
    </div>
  );
}

import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { register } from "@/services/auth";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

export default function Register() {
  const navigate = useNavigate();
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    setSubmitting(true);
    setError(null);
    try {
      const data = (await register({ username, email, password })) as any;
      if (data && data.user) {
        localStorage.setItem("user", JSON.stringify(data.user));
        if (data.token) {
          localStorage.setItem("token", data.token);
        }
      }
      navigate("/");
    } catch (err: any) {
      setError(err?.response?.data?.message || "Registration failed");
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <div className="min-h-screen bg-[#050505] text-gray-100 flex items-center justify-center p-6">
      <form
        onSubmit={onSubmit}
        className="w-full max-w-md rounded-2xl border border-white/10 bg-[#0a0a0a] shadow-2xl p-8 space-y-5"
      >
        <div>
          <h1 className="text-2xl font-heading font-bold text-white tracking-tight">Create Account</h1>
          <p className="text-xs font-mono text-gray-400 mt-1.5">Join the CodeTrack community</p>
        </div>

        <div className="space-y-1.5">
          <label className="text-[10px] font-mono uppercase tracking-widest text-gray-500">Username</label>
          <Input
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            required
            className="rounded-xl border-white/10 bg-white/5 text-white placeholder:text-gray-500 focus-visible:ring-primary/50"
          />
        </div>

        <div className="space-y-1.5">
          <label className="text-[10px] font-mono uppercase tracking-widest text-gray-500">Email</label>
          <Input
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            type="email"
            required
            className="rounded-xl border-white/10 bg-white/5 text-white placeholder:text-gray-500 focus-visible:ring-primary/50"
          />
        </div>

        <div className="space-y-1.5">
          <label className="text-[10px] font-mono uppercase tracking-widest text-gray-500">Password</label>
          <Input
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            type="password"
            required
            className="rounded-xl border-white/10 bg-white/5 text-white placeholder:text-gray-500 focus-visible:ring-primary/50"
          />
        </div>

        {error && <p className="text-xs font-mono text-red-400">{error}</p>}

        <Button type="submit" className="w-full rounded-xl font-mono text-xs bg-white text-black hover:bg-gray-200 transition-all font-bold mt-2" disabled={submitting}>
          {submitting ? "Creating…" : "Create account"}
        </Button>

        <p className="text-xs font-mono text-gray-500 text-center mt-6">
          Already have an account?{" "}
          <Link to="/login" className="text-primary hover:text-primary/80 transition-colors font-medium hover:underline">
            Sign in
          </Link>
        </p>
      </form>
    </div>
  );
}

import { api, setToken } from "@/lib/apiClient";

export async function login(payload: { email: string; password: string }) {
  const res = await api.post("/auth/login", payload);
  setToken(res.data.token);
  return res.data as { token: string };
}

export async function register(payload: { username: string; email: string; password: string }) {
  const res = await api.post("/auth/register", payload);
  setToken(res.data.token);
  return res.data as { token: string };
}
export async function googleLogin(credential: string) {
  const res = await api.post("/auth/google", { credential });
  setToken(res.data.token);
  return res.data as { token: string; user: any };
}

import { api } from "@/lib/apiClient";

export type UserProfile = {
  _id: string;
  username: string;
  email: string;
  streak: number;
  problemsSolved: number;
  platformStats: { leetcode: number; codeforces: number; codechef: number };
};

export async function fetchProfile() {
  const res = await api.get("/user/profile");
  return res.data as UserProfile;
}

export function getDeterministicStats(username: string) {
  // Stable hash based solely on the username
  const hash = Array.from(username || "User").reduce((acc, char) => acc + char.charCodeAt(0), 0);
  const baseProblems = Math.max(10, 850 - (hash % 800)); 
  const baseStreak = Math.max(0, 60 - (hash % 60));
  
  return {
    problemsSolved: baseProblems,
    streak: baseStreak,
    platformStats: {
      leetcode: Math.floor(baseProblems * 0.45),
      codeforces: Math.floor(baseProblems * 0.35),
      codechef: Math.floor(baseProblems * 0.20),
    }
  };
}

export function populateUserData(u: any) {
  const dummy = getDeterministicStats(u.username);
  const problemsSolved = u.problemsSolved > 0 ? u.problemsSolved : dummy.problemsSolved;
  const streak = u.streak > 0 ? u.streak : dummy.streak;
  
  const hasPlatforms = u.platformStats && (u.platformStats.leetcode > 0 || u.platformStats.codeforces > 0 || u.platformStats.codechef > 0);
  const platformStats = hasPlatforms ? u.platformStats : dummy.platformStats;

  return {
    ...u,
    problemsSolved,
    streak,
    platformStats
  };
}

export async function getLeaderboard() {
  const res = await api.get("/leaderboard");
  let data = res.data as UserProfile[];
  
  // Inject consistent dummy data based on names
  data = data.map((u) => populateUserData(u) as UserProfile);

  // Sort organically
  data.sort((a, b) => b.problemsSolved - a.problemsSolved);

  return data;
}

export async function fetchUserProfile(userId: string) {
  const res = await api.get(`/users/${userId}`);
  return res.data as UserProfile;
}
